def esc(s): return re.escape(s)

KN=[(1,2),(2,1),(2,-1),(1,-2),(-1,-2),(-2,-1),(-2,1),(-1,2)]
ORTH=[(1,0),(-1,0),(0,1),(0,-1)]
DIAG=[(1,1),(1,-1),(-1,1),(-1,-1)]
KING8=ORTH+DIAG

def rights(F,T):
    o=set()
    if F==('e',1): o|={0,1}
    if F==('a',1): o|={1}
    if F==('h',1): o|={0}
    if T==('a',8): o|={3}
    if T==('h',8): o|={2}
    return o

def build(anchors, edits, tag='_', ep_new='-', cast_out=frozenset(), cast_req=None, ep_pat=None):
    anchors=sorted(anchors, key=lambda a: SIDX[a['sq']])
    g=0; pat=['^']; recon=[]; cand=[]
    g+=1; pat.append('([^#\n]*?)'); recon.append('\\g<%d>'%g); cand.append('\\g<%d>'%g)
    for a in anchors:
        f,r=a['sq']; lbl=f+str(r)
        if 'lit' in a:
            pat.append(lbl+a['lit']); orig=lbl+a['lit'].replace('\\','')
        else:
            g+=1; pat.append(lbl+a['cls']); orig=lbl+'\\g<%d>'%g
        recon.append(orig)
        cand.append(lbl+edits[a['sq']] if a['sq'] in edits else orig)
        g+=1; pat.append('([^#\n]*?)'); recon.append('\\g<%d>'%g); cand.append('\\g<%d>'%g)
    cr=cast_req or '(.)(.)(.)(.)'
    ep=ep_pat or '([a-h-])'
    pat.append('#w#'+cr+'#'+ep+'(?=\n|$)')
    gK,gQ,gk,gq,gep=g+1,g+2,g+3,g+4,g+5
    metarecon='#w#'+''.join('\\g<%d>'%x for x in (gK,gQ,gk,gq))+'#\\g<%d>'%gep
    slots=['\\g<%d>'%gK,'\\g<%d>'%gQ,'\\g<%d>'%gk,'\\g<%d>'%gq]
    for i in cast_out: slots[i]='.'
    metacand='#b#'+''.join(slots)+'#'+ep_new
    return (''.join(pat), ''.join(recon)+metarecon+'\\n@'+tag+''.join(cand)+metacand)

