                cells=[(FILES[fi+df*j]+str(r+dr*j),'\\.') for j in range(1,k)]
                cells.append((FILES[af]+str(ar),cls))
                cells.sort(key=lambda c:SIDX[(c[0][0],int(c[0][1]))])
                frags.append('[^\\n]*?'.join(l+p for l,p in cells))
